ValidationRule.errorConditionFormula:
And(
          Split_Kicker__c ,
     OR(
          ISBLANK(   Split_Kicker_ARR_Threshold__c ),
/*          ISBLANK(   Split_Kicker_Duration_months__c ),*/
          ISBLANK(   Split_Kicker_Advisor_Take_Rate__c )

     ),
     OR(
          ISPICKVAL( StageName, "Joined"),
          ISPICKVAL( StageName, "Signed")
     )
)
